#include <bits/stdc++.h>
using namespace std;
int main(){
    int t;
    cin>>t;
    if(t==1)
        cout<<"I love Luogu!";
    else if(t==2)
        cout<<6<<' '<<4;
    else if(t==3)
        cout<<3<<'\n'<<12<<'\n'<<2;
    else if(t==4){
        double p=500.0/3.0;
        printf("%.3lf",p);
    }else if(t==5)
        cout<<480/32;
    else if(t==6)
        cout<<sqrt(6*6+9*9);
    else if(t==7){
        cout<<110<<endl<<90<<endl<<0;
    }else if(t==8){
        double r=5.0,p=3.141593;
        cout<<2*p*r<<'\n'<<p*r*r<<'\n'<<4.0/3.0*p*r*r*r;
    }else if(t==9){
        cout<<22;
    }else if(t==10){
        cout<<9;
    }else if(t==11){
        cout<<100.0/3;
    }else if(t==12){
        cout<<'m'-'a'+1<<endl<<char('A'+18-1);
    }else if(t==13){
        double p=3.141593;
        cout<<int(pow(4.0/3.0*p*4.0*4.0*4.0+4.0/3.0*p*10.0*10.0*10.0,1.0/3));
    }else{
        int a=-1,b=100,c=-2400;
        cout<<min((-b+sqrt(b*b-4*a*c))/(2*a),(-b-sqrt(b*b-4*a*c))/(2*a));
    }
    return 0;
}
